public void testMultipleClassKeys() throws IOException
{
    Map<Class<?>,Integer> map = new LinkedHashMap<Class<?>,Integer>();
    map.put(Integer.class, 1);
    map.put(Double.class, 2);
    map.put(Boolean.class, 3);
    String json = MAPPER.writeValueAsString(map);
    assertEquals(aposToQuotes("{'java.lang.Integer':1,'java.lang.Double':2,'java.lang.Boolean':3}"), json);
}

public void testPrimitiveClassKeys() throws IOException
{
    Map<Class<?>,String> map = new LinkedHashMap<Class<?>,String>();
    map.put(int.class, "int");
    map.put(long.class, "long");
    String json = MAPPER.writeValueAsString(map);
    assertEquals(aposToQuotes("{'int':'int','long':'long'}"), json);
}

public void testArrayClassKey() throws IOException
{
    Map<Class<?>,String> map = new LinkedHashMap<Class<?>,String>();
    map.put(String[].class, "array");
    String json = MAPPER.writeValueAsString(map);
    assertEquals(aposToQuotes("{'[Ljava.lang.String;':'array'}"), json);
}
